class DiskCache:
    def __init__(self, cache_dir: str = "cache", default_ttl: int = 3600):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)
        self.default_ttl = default_ttl
        
    def _get_cache_key(self, key: str) -> str:
        return hashlib.md5(key.encode()).hexdigest()
    
    def _get_cache_path(self, cache_key: str) -> Path:
        return self.cache_dir / f"{cache_key}.json"
    
    def _validate_data(self, data: Any) -> bool:
        if data is None:
            return True
        if isinstance(data, (str, int, float, bool)):
            return True
        if isinstance(data, list):
            return all(self._validate_data(item) for item in data)
        if isinstance(data, dict):
            return all(
                isinstance(k, str) and self._validate_data(v) 
                for k, v in data.items()
            )
        return False
    
    def set(self, key: str, value: Any, ttl: Optional[int] = None) -> bool:
        if not self._validate_data(value):
            raise ValueError("Invalid data structure: only JSON-serializable types allowed")
        
        cache_key = self._get_cache_key(key)
        cache_path = self._get_cache_path(cache_key)
        
        ttl = ttl if ttl is not None else self.default_ttl
        expiry_time = time.time() + ttl
        
        cache_data = {
            "key": key,
            "value": value,
            "expiry": expiry_time,
            "created_at": time.time()
        }
        
        try:
            with open(cache_path, 'w') as f:
                json.dump(cache_data, f, separators=(',', ':'))
            return True
        except (IOError, TypeError, ValueError) as e:
            print(f"Error writing cache: {e}")
            return False
    
    def get(self, key: str) -> Optional[Any]:
        cache_key = self._get_cache_key(key)
        cache_path = self._get_cache_path(cache_key)
        
        if not cache_path.exists():
            return None
        
        try:
            with open(cache_path, 'r') as f:
                cache_data = json.load(f)
            
            if not isinstance(cache_data, dict):
                self.delete(key)
                return None
            
            required_keys = {"key", "value", "expiry", "created_at"}
            if not required_keys.issubset(cache_data.keys()):
                self.delete(key)
                return None
            
            if not isinstance(cache_data["expiry"], (int, float)):
                self.delete(key)
                return None
            
            if time.time() > cache_data["expiry"]:
                self.delete(key)
                return None
            
            if cache_data["key"] != key:
                self.delete(key)
                return None
            
            if not self._validate_data(cache_data["value"]):
                self.delete(key)
                return None
            
            return cache_data["value"]
            
        except (IOError, json.JSONDecodeError, KeyError, TypeError) as e:
            print(f"Error reading cache: {e}")
            self.delete(key)
            return None
    
    def delete(self, key: str) -> bool:
        cache_key = self._get_cache_key(key)
        cache_path = self._get_cache_path(cache_key)
        
        try:
            if cache_path.exists():
                cache_path.unlink()
            return True
        except IOError as e:
            print(f"Error deleting cache: {e}")
            return False
    
    def clear(self) -> int:
        count = 0
        for cache_file in self.cache_dir.glob("*.json"):
            try:
                cache_file.unlink()
                count += 1
            except IOError:
                pass
        return count
    
    def cleanup_expired(self) -> int:
        count = 0
        current_time = time.time()
        
        for cache_file in self.cache_dir.glob("*.json"):
            try:
                with open(cache_file, 'r') as f:
                    cache_data = json.load(f)
                
                if isinstance(cache_data, dict) and "expiry" in cache_data:
                    if current_time > cache_data["expiry"]:
                        cache_file.unlink()
                        count += 1
            except (IOError, json.JSONDecodeError):
                pass
        
        return count


cache = DiskCache(cache_dir="api_cache", default_ttl=300)


def cached_response(ttl: Optional[int] = None, key_prefix: str = ""):
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key_parts = [key_prefix, f.__name__, request.path]
            
            if request.args:
                sorted_args = sorted(request.args.items())
                cache_key_parts.append(str(sorted_args))
            
            if request.is_json and request.get_json(silent=True):
                json_data = request.get_json()
                cache_key_parts.append(json.dumps(json_data, sort_keys=True))
            
            cache_key = ":".join(cache_key_parts)
            
            cached_data = cache.get(cache_key)
            if cached_data is not None:
                return jsonify({
                    "data": cached_data,
                    "cached": True,
                    "timestamp": time.time()
                })
            
            result = f(*args, **kwargs)
            
            if isinstance(result, tuple):
                response_data, status_code = result
            else:
                response_data = result
                status_code = 200
            
            if status_code == 200:
                if hasattr(response_data, 'get_json'):
                    data_to_cache = response_data.get_json()
                elif isinstance(response_data, dict):
                    data_to_cache = response_data
                else:
                    data_to_cache = None
                
                if data_to_cache is not None:
                    cache.set(cache_key, data_to_cache, ttl=ttl)
            
            return result
        
        return decorated_function
    return decorator


